{
  "title": "स्वचालित रोलबैक",
  "group": "लेनदेन",
  "options": [
    {
      "text": "साइड एफेक्ट्स पर निर्भर करता है",
      "hint": "सबसे सही उत्तर है"
    },
    {
      "text": "सभी बयानों को वापस ले लेता है"
    },
    {
      "text": "केवल पहले बयान को कमिट करता है"
    },
    {
      "text": "सभी सफल बयानों को कमिट करता है"
    }
  ],
  "questionProse": [
    "साइड एफेक्ट्स पर निर्भर करने वाले को छोड़कर \n    त्रुटि के बाद क्या होता है?"
  ],
  "explanationProse": [
    "जब यहां एक त्रुटि आती है:\n    - **पूरी** लेनदेन वापस ले ली जाती है\n    - कोई भी परिवर्तन कमिट नहीं होता है\n    - लेनदेन विफल चिहित कर दिया जाता है\n\n    आंशिक कमिट करने के लिए:"
  ]
}
